from __future__ import annotations
import base64
import zlib
from pathlib import Path

ROOT = Path(__file__).resolve().parents[2]
PATCH_MARKER = "batch55b-admin-category-subcategory-brand-protection"

FILES = {
    'backend/app/models/category.py':
        '',
    'backend/app/models/product.py':
        '',
    'backend/app/services/category_service.py':
        '',
    'backend/app/services/product_service.py':
        '',
    'backend/app/services/brand_service.py':
        '',
    'frontend/admin/assets/js/admin-catalog.js':
        '',
    'docs/phase8_batch55b_admin_category_subcategory_brand_protection.md':
        '',
    'README_PHASE8_BATCH55B_ADMIN_CATEGORY_SUBCATEGORY_BRAND_PROTECTION.txt':
        '',
}


def write_file(relative_path: str, encoded: str) -> None:
    target = ROOT / relative_path
    target.parent.mkdir(parents=True, exist_ok=True)
    content = zlib.decompress(base64.b64decode(encoded))
    target.write_bytes(content)
    print(f"[ok] Wrote {relative_path}")


def main() -> None:
    for relative_path, encoded in FILES.items():
        write_file(relative_path, encoded)
    print("[done] Batch 55B admin category/subcategory/brand protection polish applied.")
    print("[note] No DynamoDB tables were deleted, no counters were reset, and no S3/upload storage was enabled.")


if __name__ == "__main__":
    main()
